import olympiad; size(200); import geometry; import graph; defaultpen(linewidth(0.8));
pair A = origin, B = (10*sqrt(3),10), C = (10*sqrt(3) + 10,0);
draw(Label("$20$",align=NW),A--B); draw(B--C); draw(A--C);
